    spinLock(&postulacionLock);
}

static void unlockPostulaciones(void) {
    spinUnlock((int *)&postulacionLock);
}

void iniciarPostulaciones() {
    lockPostulaciones();
    for (int i = 0; i < N; i++) {
        if (priQueue[i] != NULL) {
            destroyPriQueue(priQueue[i]);
        }
        priQueue[i] = makePriQueue();
        postulacionTrabajos[i] = -1;
    }
    unlockPostulaciones();
}

void destruirPostulaciones() {
    lockPostulaciones();
    for (int i = 0; i < N; i++) {
        if (priQueue[i] != NULL) {
            destroyPriQueue(priQueue[i]);
            priQueue[i] = NULL;
        }
    }
    unlockPostulaciones();
}

