    Postulacion *postulacion = malloc(sizeof(Postulacion));
    postulacion->est = est;
    postulacion->ranking = rank;

    *(volatile int *)&est->trabajo_id = -1;

    lockPostulaciones();
    for (int i = 0; i < N; i++) {
        if (preferencias[i] && postulacionTrabajos[i] == -1) {
            priPut(priQueue[i], postulacion, rank[i]);
        }
    }
    unlockPostulaciones();

    while (*(volatile int *)&est->trabajo_id == -1) {
        ;
    }

    free(postulacion);
}

int cerrarPostulacion(int i) {
    int resultado;

    for (;;) {
        lockPostulaciones();

        if (postulacionTrabajos[i] != -1) {
            resultado = postulacionTrabajos[i];
            unlockPostulaciones();
            return resultado;
        }

        if (!emptyPriQueue(priQueue[i])) {
            Postulacion *postulacion = priGet(priQueue[i]);
            if (*(volatile int *)&postulacion->est->trabajo_id == -1) {
                postulacionTrabajos[i] = postulacion->est->id;
                for (int j = 0; j < N; j++) {
                    if (j != i) {
                        priDel(priQueue[j], postulacion);
                    }
                }
                *(volatile int *)&postulacion->est->trabajo_id = i;
                resultado = postulacionTrabajos[i];
                unlockPostulaciones();
                return resultado;
            }
        }

        unlockPostulaciones();
    }
}

