    free(postulacion);
}

int cerrarPostulacion(int i) {
    int resultado;

    for (;;) {
        lockPostulaciones();

        if (postulacionTrabajos[i] != -1) {
            resultado = postulacionTrabajos[i];
            unlockPostulaciones();
            return resultado;
        }

        if (!emptyPriQueue(priQueue[i])) {
            Postulacion *postulacion = priGet(priQueue[i]);
            if (*(volatile int *)&postulacion->est->trabajo_id == -1) {
                postulacionTrabajos[i] = postulacion->est->id;
                for (int j = 0; j < N; j++) {
                    if (j != i) {
                        priDel(priQueue[j], postulacion);
                    }
                }
                *(volatile int *)&postulacion->est->trabajo_id = i;
                postulacion->finalizada = 1;
                resultado = postulacionTrabajos[i];
                unlockPostulaciones();
                return resultado;
            }
        }

        unlockPostulaciones();
    }
}
